  });

  group('Multibrot shader assets', () {
    test('catalog multibrot assets exist on disk', () {
      final assets = escapeTimeShaderAssetsStartingWith(shaderRoot);

      expect(assets, isNotEmpty);
      expectAssetsExist(assets);
